#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <arpa/inet.h>

#define PORT 8080
#define BUFFER_SIZE 1024

int main() {
 int server_fd, client_fd;
 struct sockaddr_in address;
 int opt = 1;
 char buffer[BUFFER_SIZE];
 socklen_t addrlen = sizeof(address);

 // Create socket
 if ((server_fd = socket(AF_INET, SOCK_STREAM, 0)) < 0) {
 perror("socket failed");
 exit(EXIT_FAILURE);
 }

 // Set socket options to reuse address
 if (setsockopt(server_fd, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt))) {
 perror("setsockopt");
 exit(EXIT_FAILURE);
 }

 // Bind socket to port
 address.sin_family = AF_INET;
 address.sin_addr.s_addr = INADDR_ANY;
 address.sin_port = htons(PORT);

 if (bind(server_fd, (struct sockaddr *)&address, sizeof(address)) < 0) {
 perror("bind failed");
 exit(EXIT_FAILURE);
 }

 // Listen for connections
 if (listen(server_fd, 5) < 0) {
 perror("listen");
 exit(EXIT_FAILURE);
 }

 printf("Server listening on port %d\n", PORT);

 // Accept one client at a time (iterative)
 while (1) {
 client_fd = accept(server_fd, (struct sockaddr *)&address, &addrlen);
 if (client_fd < 0) {
 perror("accept");
 continue;
 }

 printf("Client connected\n");

 // Echo loop
 ssize_t n;
 while ((n = recv(client_fd, buffer, BUFFER_SIZE, 0)) > 0) {
 send(client_fd, buffer, n, 0);
 }

 close(client_fd);
 printf("Client disconnected\n");
 }

 close(server_fd);
 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <arpa/inet.h>

#define PORT 8080
#define BUFFER_SIZE 1024

int main() {
 int sock = 0;
 struct sockaddr_in serv_addr;
 char *message = "Hello from client";
 char buffer[BUFFER_SIZE] = {0};

 // Create socket
 if ((sock = socket(AF_INET, SOCK_STREAM, 0)) < 0) {
 perror("Socket creation error");
 return -1;
 }

 // Configure server address
 serv_addr.sin_family = AF_INET;
 serv_addr.sin_port = htons(PORT);

 // Convert IP address from text to binary
 if (inet_pton(AF_INET, "127.0.0.1", &serv_addr.sin_addr) <= 0) {
 perror("Invalid address");
 return -1;
 }

 // Connect to server
 if (connect(sock, (struct sockaddr *)&serv_addr, sizeof(serv_addr)) < 0) {
 perror("Connection failed");
 return -1;
 }

 printf("Connected to server\n");

 // Send message
 send(sock, message, strlen(message), 0);
 printf("Message sent\n");

 // Receive response
 ssize_t valread = read(sock, buffer, BUFFER_SIZE);
 printf("Server replied: %s\n", buffer);

 close(sock);
 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <signal.h>
#include <arpa/inet.h>
#include <sys/wait.h>

#define PORT 8080
#define BUFFER_SIZE 1024

void handle_client(int client_fd) {
 char buffer[BUFFER_SIZE];
 ssize_t n;

 printf("Child handling client\n");

 while ((n = recv(client_fd, buffer, BUFFER_SIZE, 0)) > 0) {
 send(client_fd, buffer, n, 0);
 }

 close(client_fd);
 printf("Client handler finished\n");
}

int main() {
 int server_fd, client_fd;
 struct sockaddr_in address;
 int opt = 1;
 socklen_t addrlen = sizeof(address);

 // Prevent zombie processes
 signal(SIGCHLD, SIG_IGN);

 // Create socket
 if ((server_fd = socket(AF_INET, SOCK_STREAM, 0)) < 0) {
 perror("socket failed");
 exit(EXIT_FAILURE);
 }

 // Set SO_REUSEADDR
 setsockopt(server_fd, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));

 // Bind
 address.sin_family = AF_INET;
 address.sin_addr.s_addr = INADDR_ANY;
 address.sin_port = htons(PORT);

 bind(server_fd, (struct sockaddr *)&address, sizeof(address));
 listen(server_fd, 5);

 printf("Concurrent server listening on port %d\n", PORT);

 while (1) {
 client_fd = accept(server_fd, (struct sockaddr *)&address, &addrlen);
 if (client_fd < 0) {
 perror("accept");
 continue;
 }

 pid_t pid = fork();

 if (pid < 0) {
 perror("fork failed");
 close(client_fd);
 continue;
 }

 if (pid == 0) {
 // Child process
 close(server_fd); // Close listening socket in child
 handle_client(client_fd);
 exit(0); // Exit child process
 } else {
 // Parent process
 close(client_fd); // Close client socket in parent
 }
 }

 close(server_fd);
 return 0;
}
